BEGIN;
CREATE EXTENSION IF NOT EXISTS pgcrypto;
CREATE TABLE IF NOT EXISTS public.revenue_os_ai_providers(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),provider_code text NOT NULL UNIQUE,display_name text NOT NULL,status text NOT NULL DEFAULT 'configured' CHECK(status IN('configured','available','degraded','quota_exhausted','unavailable','disabled')),execution_mode text NOT NULL DEFAULT 'shadow' CHECK(execution_mode='shadow'),external_actions_enabled boolean NOT NULL DEFAULT false,metadata jsonb NOT NULL DEFAULT '{}'::jsonb,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.revenue_os_ai_models(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),provider_code text NOT NULL REFERENCES public.revenue_os_ai_providers(provider_code) ON DELETE CASCADE,model_id text NOT NULL,role text NOT NULL CHECK(role IN('primary','fallback')),enabled boolean NOT NULL DEFAULT true,supports_structured_output boolean NOT NULL DEFAULT true,supports_tools boolean NOT NULL DEFAULT true,max_output_tokens integer NOT NULL DEFAULT 12000,health_status text NOT NULL DEFAULT 'unknown',metadata jsonb NOT NULL DEFAULT '{}'::jsonb,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now(),UNIQUE(provider_code,model_id,role));
CREATE TABLE IF NOT EXISTS public.revenue_os_ai_prompt_versions(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),prompt_code text NOT NULL,version text NOT NULL,provider_code text NOT NULL,status text NOT NULL DEFAULT 'active',content_hash text NOT NULL,metadata jsonb NOT NULL DEFAULT '{}'::jsonb,created_at timestamptz NOT NULL DEFAULT now(),activated_at timestamptz,retired_at timestamptz,UNIQUE(prompt_code,version,provider_code));
CREATE TABLE IF NOT EXISTS public.revenue_os_ai_run_attempts(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id text NOT NULL,user_id text NOT NULL,objective_id uuid,run_id uuid,provider text NOT NULL,model text NOT NULL,prompt_code text,prompt_version text,status text NOT NULL,attempt_no integer NOT NULL DEFAULT 1,request_hash text,response_hash text,input_tokens integer NOT NULL DEFAULT 0,output_tokens integer NOT NULL DEFAULT 0,latency_ms integer NOT NULL DEFAULT 0,fallback_used boolean NOT NULL DEFAULT false,error_code text,error_message text,external_actions integer NOT NULL DEFAULT 0 CHECK(external_actions=0),created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.revenue_os_ai_quota_usage(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id text NOT NULL,user_id text NOT NULL,provider text NOT NULL,model text NOT NULL,request_count integer NOT NULL DEFAULT 1,input_tokens integer NOT NULL DEFAULT 0,output_tokens integer NOT NULL DEFAULT 0,status text NOT NULL,created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.revenue_os_ai_provider_health(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),provider text NOT NULL,model text NOT NULL,status text NOT NULL,checked_at timestamptz NOT NULL,last_success_at timestamptz,last_failure_at timestamptz,error_code text,message text,metadata jsonb NOT NULL DEFAULT '{}'::jsonb,UNIQUE(provider,model));
CREATE TABLE IF NOT EXISTS public.revenue_os_ai_response_cache(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id text NOT NULL,request_hash text NOT NULL,response_payload jsonb NOT NULL,provider text NOT NULL,model text NOT NULL,expires_at timestamptz NOT NULL,created_at timestamptz NOT NULL DEFAULT now(),UNIQUE(tenant_id,request_hash));
CREATE TABLE IF NOT EXISTS public.revenue_os_ai_jobs(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id text NOT NULL,user_id text NOT NULL,objective_id uuid,status text NOT NULL CHECK(status IN('queued','validating','assembling_context','selecting_commands','calling_provider','validating_output','repairing_output','persisting','completed','failed','retry_scheduled','quota_deferred','cancelled')),idempotency_key text NOT NULL,lease_owner text,lease_expires_at timestamptz,retry_count integer NOT NULL DEFAULT 0,next_retry_at timestamptz,cancelled_at timestamptz,completed_at timestamptz,result_ref text,error_message text,payload jsonb NOT NULL DEFAULT '{}'::jsonb,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now(),UNIQUE(tenant_id,idempotency_key));
CREATE INDEX IF NOT EXISTS revenue_os_ai_jobs_queue_idx ON public.revenue_os_ai_jobs(status,next_retry_at,created_at);
CREATE INDEX IF NOT EXISTS revenue_os_ai_jobs_tenant_idx ON public.revenue_os_ai_jobs(tenant_id,status,created_at DESC);
CREATE INDEX IF NOT EXISTS revenue_os_ai_quota_minute_idx ON public.revenue_os_ai_quota_usage(tenant_id,created_at DESC);
CREATE INDEX IF NOT EXISTS revenue_os_ai_attempts_run_idx ON public.revenue_os_ai_run_attempts(tenant_id,run_id,attempt_no);
CREATE INDEX IF NOT EXISTS revenue_os_ai_cache_expiry_idx ON public.revenue_os_ai_response_cache(expires_at);
DO $$ DECLARE t text; BEGIN FOREACH t IN ARRAY ARRAY['revenue_os_ai_providers','revenue_os_ai_models','revenue_os_ai_prompt_versions','revenue_os_ai_run_attempts','revenue_os_ai_quota_usage','revenue_os_ai_provider_health','revenue_os_ai_response_cache','revenue_os_ai_jobs'] LOOP EXECUTE format('ALTER TABLE public.%I ENABLE ROW LEVEL SECURITY',t);EXECUTE format('REVOKE ALL ON public.%I FROM anon, authenticated',t);EXECUTE format('GRANT ALL ON public.%I TO service_role',t);END LOOP;END $$;
INSERT INTO public.revenue_os_ai_providers(provider_code,display_name,status,execution_mode,external_actions_enabled,metadata) VALUES('gemini','Google Gemini','configured','shadow',false,jsonb_build_object('providerNeutralGateway',true,'structuredOutput',true,'minimumStrategies',5)) ON CONFLICT(provider_code) DO UPDATE SET status='configured',execution_mode='shadow',external_actions_enabled=false,metadata=excluded.metadata,updated_at=now();
INSERT INTO public.revenue_os_ai_providers(provider_code,display_name,status,execution_mode,external_actions_enabled,metadata) VALUES('deterministic','AngelCare Deterministic Fallback','available','shadow',false,jsonb_build_object('manualReviewRequired',true)) ON CONFLICT(provider_code) DO UPDATE SET status='available',external_actions_enabled=false,metadata=excluded.metadata,updated_at=now();
INSERT INTO public.revenue_os_ai_prompt_versions(prompt_code,version,provider_code,status,content_hash,metadata) VALUES('revenue-strategy-assembly','10.1.0','gemini','active',encode(digest('revenue-strategy-assembly:10.1.0','sha256'),'hex'),jsonb_build_object('minimumStrategies',5,'language','fr','externalActions',0)) ON CONFLICT(prompt_code,version,provider_code) DO UPDATE SET status='active',metadata=excluded.metadata;
UPDATE public.revenue_os_installations SET release_code='AC-REVENUE-OS-MZ10.1-GEMINI-STABILIZATION',module_version='10.1.0',execution_mode='shadow',contract_locked=true,external_actions_enabled=false,metadata=coalesce(metadata,'{}'::jsonb)||jsonb_build_object('currentPhase','MZ10.1','geminiGateway',true,'providerNeutral',true,'minimumCompetingStrategies',5,'externalActions',0),updated_at=now() WHERE installation_key='revenue-command-os';
DO $$ BEGIN IF NOT EXISTS(SELECT 1 FROM public.revenue_os_installations WHERE installation_key='revenue-command-os' AND release_code='AC-REVENUE-OS-MZ10.1-GEMINI-STABILIZATION' AND external_actions_enabled=false) THEN RAISE EXCEPTION 'MZ10.1 installation registry assertion failed';END IF;END $$;
COMMIT;
